import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { getTasksByProject, updateTaskStatus } from "../services/taskService";

function KanbanPage() {
  const { id } = useParams(); // 🔥 projectId

  const [tasks, setTasks] = useState([]);
  const [draggedTaskId, setDraggedTaskId] = useState(null);

  // 🔹 Fetch tasks by project
  const fetchTasks = async () => {
    try {
      const data = await getTasksByProject(id); // ⚠️ خاص service يقبل id
      setTasks(data);
    } catch (error) {
      console.error("Error fetching tasks:", error.message);
    }
  };

  useEffect(() => {
    if (id) fetchTasks();
  }, [id]);

  // 🔹 تقسيم tasks
  const todoTasks = tasks.filter((t) => t.status === "todo");
  const inProgressTasks = tasks.filter((t) => t.status === "inprogress");
  const doneTasks = tasks.filter((t) => t.status === "done");

  // 🔹 Update status
  const handleStatusChange = async (taskId, newStatus) => {
    try {
      await updateTaskStatus(taskId, newStatus);

      // update local state بلا fetch
      setTasks((prev) =>
        prev.map((t) =>
          t._id === taskId ? { ...t, status: newStatus } : t
        )
      );
    } catch (error) {
      console.error("Error updating task:", error.message);
    }
  };

  // 🔹 Drag & Drop
  const handleDrop = async (newStatus) => {
    if (!draggedTaskId) return;

    await handleStatusChange(draggedTaskId, newStatus);
    setDraggedTaskId(null);
  };

  // 🔹 Deadline logic
  const getDeadlineStatus = (deadline) => {
    if (!deadline) return null;

    const today = new Date();
    const due = new Date(deadline);

    const diff = (due - today) / (1000 * 60 * 60 * 24);

    if (diff < 0) return "overdue";
    if (diff <= 2) return "near";

    return "normal";
  };

  const renderDeadline = (task) => {
    if (task.status === "done") return null;

    const status = getDeadlineStatus(task.deadline);

    if (status === "overdue") {
      return <p style={{ color: "red" }}>Deadline dépassée</p>;
    }

    if (status === "near") {
      return <p style={{ color: "orange" }}>Deadline proche</p>;
    }

    return null;
  };

  // 🔹 Card
  const renderTask = (task) => (
    <div
      key={task._id}
      draggable
      onDragStart={() => setDraggedTaskId(task._id)}
      style={{
        background: "#fff",
        padding: "10px",
        marginBottom: "10px",
        borderRadius: "8px",
      }}
    >
      <h4>{task.title}</h4>
      <p>{task.description}</p>

      <p><strong>Priority:</strong> {task.priority}</p>

      <p>
        <strong>Deadline:</strong>{" "}
        {task.deadline ? task.deadline.slice(0, 10) : "None"}
      </p>

      {renderDeadline(task)}

      <select
        value={task.status}
        onChange={(e) =>
          handleStatusChange(task._id, e.target.value)
        }
      >
        <option value="todo">To do</option>
        <option value="inprogress">In progress</option>
        <option value="done">Done</option>
      </select>
    </div>
  );

  return (
    <div style={{ padding: "20px" }}>
      <h1>Kanban - Project</h1>

      <div style={{ display: "flex", gap: "20px" }}>
        {/* TODO */}
        <div onDragOver={(e) => e.preventDefault()} onDrop={() => handleDrop("todo")}>
          <h2>To do</h2>
          {todoTasks.map(renderTask)}
        </div>

        {/* IN PROGRESS */}
        <div onDragOver={(e) => e.preventDefault()} onDrop={() => handleDrop("inprogress")}>
          <h2>In progress</h2>
          {inProgressTasks.map(renderTask)}
        </div>

        {/* DONE */}
        <div onDragOver={(e) => e.preventDefault()} onDrop={() => handleDrop("done")}>
          <h2>Done</h2>
          {doneTasks.map(renderTask)}
        </div>
      </div>
    </div>
  );
}

export default KanbanPage;
